def fact_check(statements: list) -> dict:
    verified = []
    for statement in statements:
        # Search multiple sources
        sources = [
            search_google(statement),
            search_wikipedia(statement),
            search_enterprise_db(statement)
        ]
        verified.append({
            'statement': statement,
            'sources': sources,
            'confidence': len([s for s in sources if s['supports']]) / len(sources)
        })
    return {'facts': verified}

fact_tool = Tool(name="verify_facts", func=fact_check, max_retries=3)

from beeai.tools import Tool
import re

def seo_check(content: str, keywords: list) -> dict:
    word_count = len(re.findall(r'\w+', content))
    keyword_density = {}
    for kw in keywords:
        count = len(re.findall(re.escape(kw), content, re.IGNORECASE))
        density = (count * 100) / word_count if word_count else 0
        keyword_density[kw] = density

    return {
        'word_count': word_count,
        'keyword_density': keyword_density,
        'seo_score': sum([1 if d > 1 and d < 3 else 0 for d in keyword_density.values()]),
        'compliant': all(1 <= d <= 3 for d in keyword_density.values())
    }

seo_tool = Tool(name="seo_validate", func=seo_check)
